#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int parent;
    int rank;
} UnionFind;

void makeSet(UnionFind *uf, int v) {
    uf[v].parent = v;
    uf[v].rank = 0;
}

int find(UnionFind *uf, int x) {
    if (uf[x].parent != x) {
        uf[x].parent = find(uf, uf[x].parent);  // Path compression
    }
    return uf[x].parent;
}

void unionSets(UnionFind *uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);

    if (rootX != rootY) {
        // Union by rank
        if (uf[rootX].rank < uf[rootY].rank) {
            uf[rootX].parent = rootY;
        } else if (uf[rootX].rank > uf[rootY].rank) {
            uf[rootY].parent = rootX;
        } else {
            uf[rootY].parent = rootX;
            uf[rootX].rank++;
        }
    }
}

int sameComponent(UnionFind *uf, int x, int y) {
    return find(uf, x) == find(uf, y);
}

import java.util.*;

class Edge implements Comparable<Edge> {
    int src, dest, weight;

    Edge(int src, int dest, int weight) {
        this.src = src;
        this.dest = dest;
        this.weight = weight;
    }

    public int compareTo(Edge e) {
        return this.weight - e.weight;
    }
}

class UnionFind {
    int[] parent, rank;

    UnionFind(int n) {
        parent = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    boolean union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);

        if (rootX == rootY) return false;

        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
        return true;
    }
}

public class KruskalMST {
    public static List<Edge> kruskalMST(List<Edge> edges, int V) {
        Collections.sort(edges);

        UnionFind uf = new UnionFind(V);
        List<Edge> mst = new ArrayList<>();

        for (Edge e : edges) {
            if (uf.union(e.src, e.dest)) {
                mst.add(e);
                if (mst.size() == V - 1) break;
            }
        }
        return mst;
    }
}
